from math import factorial

FACT = [factorial(i) for i in range(10)]

# For n < 1_000_000, the next value is at most 6 * 9! = 2177280.
LIMIT = 6 * FACT[9]

memo = {1: 1, 2: 1, 145: 1, 169: 3, 871: 2, 872: 2, 363601: 3, 45361: 2, 45362: 2}


def next_num(n: int) -> int:
    s = 0
    while n:
        n, d = divmod(n, 10)
        s += FACT[d]
    return s


def chain_len(start: int) -> int:
    seen = []
    n = start
    while n not in memo and n not in seen:
        seen.append(n)
        n = next_num(n)
    if n in memo:
        length = memo[n]
    else:
        # Found a new cycle within seen
        idx = seen.index(n)
        cycle_len = len(seen) - idx
        for x in seen[idx:]:
            memo[x] = cycle_len
        length = cycle_len
        seen = seen[:idx]
    for x in reversed(seen):
        length += 1
        memo[x] = length
    return memo[start]


count = 0
for i in range(1, 1_000_000):
    if chain_len(i) == 60:
        count += 1

print(count)

