# Represent each cube as a bitmask over digits 0..9.
# Digits 6 and 9 are interchangeable, so for checking we treat presence of either as satisfying both.

squares = [(0,1),(0,4),(0,9),(1,6),(2,5),(3,6),(4,9),(6,4),(8,1)]

# Precompute all 6-digit subsets as masks.
subsets = []
for comb in combinations(range(10), 6):
    mask = 0
    for d in comb:
        mask |= 1 << d
    subsets.append(mask)


def has(mask, d):
    if d == 6 or d == 9:
        return (mask >> 6) & 1 or (mask >> 9) & 1
    return (mask >> d) & 1

count = 0
for i, a in enumerate(subsets):
    for b in subsets[i:]:
        ok = True
        for x, y in squares:
            if not ((has(a, x) and has(b, y)) or (has(a, y) and has(b, x))):
                ok = False
                break
        if ok:
            count += 1

print(count)

from fractions import Fraction
from itertools import combinations

ops = [
    lambda x, y: x + y,
    lambda x, y: x - y,
    lambda x, y: y - x,
    lambda x, y: x * y,
    lambda x, y: x / y if y != 0 else None,
    lambda x, y: y / x if x != 0 else None,
]

def results(nums):
    if len(nums) == 1:
        return {nums[0]}
    out = set()
    n = len(nums)
    # split into two non-empty groups
    for mask in range(1, 1 << n - 1):
        pass
    # recursive pairwise reduction is simpler
    if len(nums) == 2:
        a, b = nums
        for op in ops:
            try:
                r = op(a, b)
            except ZeroDivisionError:
                continue
            if r is not None:
                out.add(r)
        return out
    # choose ordered pair and reduce
    L = list(nums)
    for i in range(len(L)):
        for j in range(i + 1, len(L)):
            a, b = L[i], L[j]
            rest = [L[k] for k in range(len(L)) if k != i and k != j]
            for op in ops:
                try:
                    r = op(a, b)
                except ZeroDivisionError:
                    continue
                if r is None:
                    continue
                out |= results(rest + [r])
    return out

