from math import isqrt

LIMIT = 1_000_000

# Sum of proper divisors for every n <= LIMIT using a sieve.
sp = [0] * (LIMIT + 1)
for d in range(1, LIMIT // 2 + 1):
    for m in range(d * 2, LIMIT + 1, d):
        sp[m] += d

visited_global = [False] * (LIMIT + 1)
best_len = 0
best_min = None

for start in range(2, LIMIT + 1):
    if visited_global[start]:
        continue

    seq = []
    pos = {}
    x = start
    while True:
        if x > LIMIT or x == 0:
            break
        if x in pos:
            cycle = seq[pos[x]:]
            # Ensure all elements in the cycle are within limit (they are by loop condition)
            clen = len(cycle)
            cmin = min(cycle)
            if clen > best_len or (clen == best_len and (best_min is None or cmin < best_min)):
                best_len = clen
                best_min = cmin
            break
        if visited_global[x]:
            break
        pos[x] = len(seq)
        seq.append(x)
        x = sp[x]

    for v in seq:
        visited_global[v] = True

print(best_min)
